## Steps to reproduce the issue

```
module sync_reset_test(clk, rst, d, z);
      input clk, rst, d;
      output z;

  test_m #() my_m (
      .clk(clk),
      .arst(1'b1),
      .srst(rst),
      .d(d),
      .z(z)
    );
endmodule

module test_m (clk, arst, srst, d, z);

    input   clk;
    input   arst;
    input   srst;
    input   d;
    output  z;

    reg     q_reg;

    assign z = q_reg;

        //always @(posedge clk or posedge arst)
        always @(posedge clk or negedge arst)
        if (arst == 1'b0)
        begin
            q_reg  <= 1'b0;
        end
        else if (srst == 1'b1)
        begin
            q_reg  <= 1'b0;
        end
        else
        begin
            q_reg  <= d;
        end

endmodule
```
```
read_verilog ...
prep

```
## Expected behavior
Expect to have $dff with $mux.

## Actual behavior
Result is $adff with $mux.

Another note:
This alternative "always" with "posedge" will give you this. 
ERROR: Async reset \arst yields non-constant value 1'm for signal \q_reg.

